#include <stdio.h>

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        long long X, Y;
        scanf("%lld %lld", &X, &Y);
        if ((X + Y) % 2 == 0)
            printf("Janmansh\n");
        else
            printf("Jay\n");
    }
    return 0;
}

